import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote: base premiums
  it.todo("empty item list yields a premium of 5 G (processing fee only)");
  it.todo("a single sword (plain, newcomer first contract) yields a premium of 115 G (100 base + 10 first + 5 fee)");
  it.todo("a single amulet (plain, newcomer first contract) yields a premium of 71 G (60 base + 6 first + 5 fee)");

  // Quote: components and blocks
  it.todo("2 runes (plain, newcomer first contract) yields a premium of 60 G (50 base + 5 first + 5 fee)");
  it.todo("3 runes form a block: base premium 60 G total");
  it.todo("3 runes + 3 moonstones form two blocks: base premium 120 G total");

  // Quote: modifiers
  it.todo("a cursed sword applies +50% surcharge on the cursed item only");
  it.todo("high enchantment (level >= 5) sword applies +30% surcharge");
  it.todo("long-standing customer (>= 2 years) receives 20% loyalty discount on policy total");
  it.todo("follow-up contract receives 15% discount on policy total");
  it.todo("policy with cursed sword and plain amulet: cursed surcharge applies only to cursed item");

  // Quote: rounding and integration
  it.todo("premium is rounded up in MHPCO's favor");
  it.todo("newcomer with a cursed sword (steel, enchantment 3) yields premium of 165 G");
  it.todo("long-standing customer's second contract with cursed sword enchantment 7 yields 160 G");

  // Claim: basic
  it.todo("plain sword damage 500 G yields payout 400 G (full reimbursement minus 100 deductible)");
  it.todo("rune damage 200 G yields payout 100 G");
  it.todo("enchantment >= 8 reimburses at 50% then deductible");
  it.todo("dragon-material item is fully reimbursed before deductible");
  it.todo("dragon-material + enchantment >= 8: 50% rule wins, then deductible");
  it.todo("dragon attack damaging sword and amulet: deductible applies per damage entry");

  // Claim: cap
  it.todo("payout is capped at twice the insurance sum across multiple claims");
  it.todo("cap is based on unmodified insurance value, not modified premium");

  // Edge cases
  it.todo("quote with unknown item type causes the CLI to exit with non-zero status");
  it.todo("claim referencing damage to item not in policy causes non-zero exit");
  it.todo("claim with negative damage amount causes non-zero exit");
  it.todo("more damage entries of a type than items insured causes non-zero exit");
});

