const COMPONENT_BLOCK_BASE_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const isComponent = (item: Item): boolean => !(item.type in TYPE_BASE_PREMIUM);

const componentCountsByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const componentBaseForType = (count: number): number => {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const leftover = count % COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
};

const sumComponentPremiums = (components: Item[]): number => {
  const counts = componentCountsByType(components);
  let total = 0;
  for (const count of counts.values()) {
    total += componentBaseForType(count) * FIRST_INSURANCE_FACTOR;
  }
  return total;
};

const sumItemPremiums = (items: Item[]): number => {
  const mainItems = items.filter((i) => !isComponent(i));
  const components = items.filter(isComponent);
  return mainItems.reduce((sum, item) => sum + itemPremium(item), 0) + sumComponentPremiums(components);
};

