type Item = { type: string; cursed?: boolean; enchantment?: number };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE = 0.1;
const CURSE_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_BASE_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;

const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);

const surcharge = (base: number, applies: boolean, rate: number): number =>
  applies ? base * rate : 0;

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const mainItemPremium = (item: Item): number => {
  const base = MAIN_ITEM_BASE_PREMIUM[item.type];
  return (
    base +
    surcharge(base, item.cursed === true, CURSE_SURCHARGE) +
    surcharge(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE) +
    base * FIRST_INSURANCE_SURCHARGE
  );
};

const componentGroupBase = (count: number): number => {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const leftover = count % COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
};

const componentCountsByType = (components: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of components) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumComponentPremiums = (components: Item[]): number =>
  [...componentCountsByType(components).values()].reduce(
    (total, count) => total + componentGroupBase(count) * (1 + FIRST_INSURANCE_SURCHARGE),
    0,
  );

const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
  const mainItems: Item[] = [];
  const components: Item[] = [];
  for (const item of items) {
    (isMainItem(item) ? mainItems : components).push(item);
  }
  return { mainItems, components };
};

const sumMainItemPremiums = (mainItems: Item[]): number =>
  mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);

const sumItemPremiums = (items: Item[]): number => {
  const { mainItems, components } = partitionItems(items);
  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
};

const priceQuote = (step: QuoteStep): { premium: number } => ({
  premium: ceilWithEpsilon(sumItemPremiums(step.items) + PROCESSING_FEE),
});

export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
  results: scenario.steps.map(priceQuote),
});

