const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const LOYALTY_DISCOUNT = 0.2;
const LOYALTY_YEARS_THRESHOLD = 2;
const COMPONENT_BASE_PREMIUM = 25;
const COMPONENT_BLOCK_BASE_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;

const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);

const surcharge = (base: number, applies: boolean, rate: number): number =>
  applies ? base * rate : 0;

const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const mainItemBase = (item: Item): number => MAIN_ITEM_BASE_PREMIUM[item.type];

const mainItemPremium = (item: Item): number => {
