  const itemsTotal = sumItemPremiums(step.items);
  const loyalty = surcharge(policyBasePremium(step.items), isLoyalCustomer(customer), LOYALTY_DISCOUNT);
  return { premium: ceilWithEpsilon(itemsTotal - loyalty + PROCESSING_FEE) };
};

