const componentCountsByType = (components: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of components) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumComponentGroupBases = (components: Item[]): number =>
  [...componentCountsByType(components).values()].reduce(
    (total, count) => total + componentGroupBase(count),
    0,
  );

const sumComponentPremiums = (components: Item[]): number =>
  sumComponentGroupBases(components) * (1 + FIRST_INSURANCE_SURCHARGE);

const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
  const mainItems: Item[] = [];
  const components: Item[] = [];
  for (const item of items) {
    (isMainItem(item) ? mainItems : components).push(item);
  }
  return { mainItems, components };
};

const sumMainItemPremiums = (mainItems: Item[]): number =>
  mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);

const sumMainItemBases = (mainItems: Item[]): number =>
  mainItems.reduce((sum, item) => sum + mainItemBase(item), 0);

const policyBasePremium = (items: Item[]): number => {
  const { mainItems, components } = partitionItems(items);
  return sumMainItemBases(mainItems) + sumComponentGroupBases(components);
};

const sumItemPremiums = (items: Item[]): number => {
  const { mainItems, components } = partitionItems(items);
  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
};

const isLoyalCustomer = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;

const priceQuote = (step: QuoteStep, customer: Customer): { premium: number } => {
  const itemsTotal = sumItemPremiums(step.items);
  const loyalty = surcharge(policyBasePremium(step.items), isLoyalCustomer(customer), LOYALTY_DISCOUNT);
  return { premium: ceilWithEpsilon(itemsTotal - loyalty + PROCESSING_FEE) };
};

export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
  results: scenario.steps.map((step) => priceQuote(step, scenario.customer)),
});

